{"path":"/root/.hermes/scripts/daily_email_report.py","content":"#!/usr/bin/env python3
"""
Daily Email Report - pcccthanglong.tlc@gmail.com
Outputs raw structured data for AI to translate and format.

Attachment handling:
- Downloads Gmail attachments to a local cache.
- Attempts to upload attachments to Google Drive folder Hermes Email Attachments/YYYY-MM-DD.
- Extracts text from PDF attachments with pdftotext for AI summarization.
"""

import base64
import importlib.util
import json
import os
import re
import shutil
import subprocess
import sys
from datetime import datetime, timezone, timedelta
from pathlib import Path

GAPI = "/root/.hermes/skills/productivity/google-workspace/scripts/google_api.py"
GWS_BIN = "/root/.local/bin/gws"
TZ_VN = timezone(timedelta(hours=7))
ATTACH_ROOT = Path("/root/.hermes/email_attachments")
DRIVE_ROOT_FOLDER = "Hermes Email Attachments"
MAX_PDF_TEXT_CHARS = 5000

API_ENV = {
    "PATH": "/usr/bin:/bin:/root/.local/bin",
    "HERMES_GWS_BIN": GWS_BIN,
    "HOME": "/root",
    "HERMES_HOME": "/root/.hermes",
}


def load_google_api_module():
    spec = importlib.util.spec_from_file_location("hermes_google_api", GAPI)
    mod = importlib.util.module_from_spec(spec)
    spec.loader.exec_module(mod)
    return mod


def build_service(api, version):
    mod = load_google_api_module()
    return mod.build_service(api, version)


def run_gmail(query, max_results=50):
    result = subprocess.run(
        [sys.executable, GAPI, "gmail", "search", query, "--max", str(max_results)],
        capture_output=True,
        text=True,
        env=API_ENV,
    )
    try:
        data = json.loads(result.stdout)
        return data if isinstance(data, list) else []
    except Exception:
        return []


def get_full_message(service, msg_id):
    try:
        return service.users().messages().get(userId="me", id=msg_id, format="full").execute()
    except Exception:
        return {}


def headers_dict(msg):
    return {h.get("name", ""): h.get("value", "") for h in msg.get("payload", {}).get("headers", [])}


def decode_body_data(data):
    if not data:
        return ""
    try:
        return base64.urlsafe_b64decode(data.encode("utf-8")).decode("utf-8", errors="replace")
    except Exception:
        return ""


def walk_parts(part):
    if not part:
        return
    yield part
    for child in part.get("parts", []) or []:
        yield from walk_parts(child)


def extract_message_body(full_msg):
    payload = full_msg.get("payload", {})
    html_fallback = ""
    for part in walk_parts(payload):
        mime = part.get("mimeType", "")
        data = part.get("body", {}).get("data", "")
        if mime == "text/plain" and data:
            return decode_body_data(data)
        if mime == "text/html" and data and not html_fallback:
            html_fallback = decode_body_data(data)
    return html_fallback


def safe_filename(name):
    name = name or "attachment"
    name = re.sub(r"[\\/:*?\"<>|\r\n]+", "_", name).strip()
    return name[:180] or "attachment"


def ensure_unique_path(path):
    if not path.exists():
        return path
    stem, suffix = path.stem, path.suffix
    for i in range(2, 1000):
        candidate = path.with_name(f"{stem}_{i}{suffix}")
        if not candidate.exists():
            return candidate
    return path.with_name(f"{stem}_{int(datetime.now().timestamp())}{suffix}")


def find_or_create_drive_folder(drive_service, name, parent_id=None):
    # Requires Drive write scope. If token only has drive.readonly this raises 403; caller handles it.
    escaped = name.replace("'", "\\'")
    q = (
        f"name='{escaped}' and mimeType='application/vnd.google-apps.folder' "
        "and trashed=false"
    )
    if parent_id:
        q += f" and '{parent_id}' in parents"
    result = drive_service.files().list(q=q, pageSize=1, fields="files(id,name,webViewLink)").execute()
    files = result.get("files", [])
    if files:
        return files[0]
    metadata = {"name": name, "mimeType": "application/vnd.google-apps.folder"}
    if parent_id:
        metadata["parents"] = [parent_id]
    return drive_service.files().create(body=metadata, fields="id,name,webViewLink").execute()


def upload_to_drive(path, report_date_folder):
    try:
        from googleapiclient.http import MediaFileUpload
        drive = build_service("drive", "v3")
        root = find_or_create_drive_folder(drive, DRIVE_ROOT_FOLDER)
        day_folder = find_or_create_drive_folder(drive, report_date_folder, root["id"])
        media = MediaFileUpload(str(path), resumable=False)
        metadata = {"name": path.name, "parents": [day_folder["id"]]}
        uploaded = drive.files().create(
            body=metadata,
            media_body=media,
            fields="id,name,mimeType,webViewLink,webContentLink",
        ).execute()
        return {
            "status": "uploaded",
            "drive_file_id": uploaded.get("id", ""),
            "drive_link": uploaded.get("webViewLink", ""),
            "drive_download_link": uploaded.get("webContentLink", ""),
            "drive_folder": f"{DRIVE_ROOT_FOLDER}/{report_date_folder}",
        }
    except Exception as e:
        return {
            "status": "local_saved_drive_upload_failed",
            "error": str(e)[:500],
            "drive_folder": f"{DRIVE_ROOT_FOLDER}/{report_date_folder}",
        }


def extract_pdf_text(path):
    if path.suffix.lower() != ".pdf":
        return ""
    if not shutil.which("pdftotext"):
        return ""
    try:
        result = subprocess.run(
            ["pdftotext", "-layout", str(path), "-"],
            capture_output=True,
            text=True,
            timeout=30,
        )
        text = result.stdout.strip()
        text = re.sub(r"\n{3,}", "\n\n", text)
        return text[:MAX_PDF_TEXT_CHARS]
    except Exception:
        return ""


def download_attachments(gmail_service, full_msg, report_date_folder):
    msg_id = full_msg.get("id", "")
    subject = headers_dict(full_msg).get("Subject", "")
    msg_dir = ATTACH_ROOT / report_date_folder / msg_id
    msg_dir.mkdir(parents=True, exist_ok=True)

    attachments = []
    for part in walk_parts(full_msg.get("payload", {})):
        filename = part.get("filename") or ""
        body = part.get("body", {}) or {}
        attachment_id = body.get("attachmentId")
        if not filename or not attachment_id:
            continue
        clean_name = safe_filename(filename)
        local_path = ensure_unique_path(msg_dir / clean_name)
        item = {
            "original_filename": filename,
            "local_saved": False,
            "local_path": str(local_path),
            "mime_type": part.get("mimeType", ""),
            "size_bytes": body.get("size", 0),
            "is_pdf": clean_name.lower().endswith(".pdf") or part.get("mimeType") == "application/pdf",
            "source_email_subject": subject,
        }
        try:
            att = gmail_service.users().messages().attachments().get(
                userId="me", messageId=msg_id, id=attachment_id
            ).execute()
            raw = base64.urlsafe_b64decode(att.get("data", "").encode("utf-8"))
            local_path.write_bytes(raw)
            item["local_saved"] = True
            item["size_bytes"] = len(raw)
            item.update(upload_to_drive(local_path, report_date_folder))
            if item["is_pdf"]:
                item["pdf_text_for_summary"] = extract_pdf_text(local_path)
                item["pdf_text_extracted"] = bool(item.get("pdf_text_for_summary"))
        except Exception as e:
            item["status"] = "download_failed"
            item["error"] = str(e)[:500]
        attachments.append(item)
    return attachments


def clean_body(text, max_len=1000):
    """Extract meaningful content, remove signatures/footers."""
    if not text:
        return ""
    lines = []
    for line in text.splitlines():
        line = line.strip()
        if not line:
            continue
        low = line.lower()
        if any(marker in low for marker in [
            "unsubscribe", "click here", "view in browser", "privacy policy",
            "©", "copyright", "all rights reserved", "sent from my", "get outlook",
            "________________________________", "---", "___",
            "https://", "http://", "www.",
        ]):
            continue
        lines.append(line)

    text = "\n".join(lines)
    if len(text) > max_len:
        text = text[:max_len] + "..."
    return text.strip()


def format_date(date_str):
    try:
        from email.utils import parsedate_to_datetime
        dt = parsedate_to_datetime(date_str)
        dt_vn = dt.astimezone(TZ_VN)
        days_vn = ["Thứ Hai", "Thứ Ba", "Thứ Tư", "Thứ Năm", "Thứ Sáu", "Thứ Bảy", "Chủ Nhật"]
        day_name = days_vn[dt_vn.weekday()]
        return f"{day_name}, {dt_vn.strftime('%d/%m/%Y %H:%M')}"
    except Exception:
        return date_str


def build_email_item(msg, full_msg, gmail_service, report_date_folder, direction):
    body = extract_message_body(full_msg) or msg.get("snippet", "")
    item = {
        "subject": msg.get("subject", "(Không có tiêu đề)"),
        "date": format_date(msg.get("date", "")),
        "body": clean_body(body),
        "attachments": download_attachments(gmail_service, full_msg, report_date_folder),
    }
    if direction == "inbox":
        item["from"] = msg.get("from", "N/A")
        item["to"] = msg.get("to", "N/A")
    else:
        item["to"] = msg.get("to", "N/A")
    return item


def main():
    now = datetime.now(TZ_VN)
    report_date = now.strftime("%d/%m/%Y")
    report_date_folder = now.strftime("%Y-%m-%d")
    report_day = ["Thứ Hai", "Thứ Ba", "Thứ Tư", "Thứ Năm", "Thứ Sáu", "Thứ Bảy", "Chủ Nhật"][now.weekday()]

    inbox = run_gmail("in:inbox newer_than:1d", max_results=30)
    sent = run_gmail("in:sent newer_than:1d", max_results=30)

    gmail_service = build_service("gmail", "v1")

    out = {
        "meta": {
            "account": "pcccthanglong.tlc@gmail.com",
            "date": report_date,
            "day": report_day,
            "time": now.strftime("%H:%M"),
            "inbox_count": len(inbox),
            "sent_count": len(sent),
            "attachment_policy": "Attachments are saved locally first, then uploaded to Google Drive when Drive write scope is available.",
            "drive_target_folder": f"{DRIVE_ROOT_FOLDER}/{report_date_folder}",
        },
        "inbox": [],
        "sent": [],
    }

    for msg in inbox:
        full = get_full_message(gmail_service, msg.get("id", ""))
        out["inbox"].append(build_email_item(msg, full, gmail_service, report_date_folder, "inbox"))

    for msg in sent:
        full = get_full_message(gmail_service, msg.get("id", ""))
        out["sent"].append(build_email_item(msg, full, gmail_service, report_date_folder, "sent"))

    print(json.dumps(out, ensure_ascii=False, indent=2))


if __name__ == "__main__":
    main()
"}

